// 82 حدثاً مرتّبة زمنياً من يونيو 1914 إلى ما بعد الحرب
export const WW1_EVENTS: HistoricalEvent[] = [
  {id:"e1",orderIndex:1,category:"الحرب العالمية الأولى",title:"اغتيال ولي عهد النمسا والمجر (فرانز فرديناند)",gregorianDate:"28 يونيو 1914 م",hijriDate:"4 شعبان 1332 هـ",location:"سراييفو (البوسنة)",description:"قام طالب صربي قومي يُدعى \"غافريلو برينسيب\" باغتيال ولي عهد الإمبراطورية النمساوية المجرية وزوجته. كان هذا الحدث بمثابة الشرارة المباشرة التي أشعلت فتيل التوترات المتراكمة في أوروبا.",strategicSignificance:"أدى هذا الاغتيال إلى توجيه النمسا والمجر إنذاراً شديد اللهجة لصربيا، مما دفع التحالفات الأوروبية للتدخل وتصعيد الأزمة."},
  {id:"e2",orderIndex:2,category:"الحرب العالمية الأولى",title:"إعلان النمسا والمجر الحرب على صربيا",gregorianDate:"28 يوليو 1914 م",hijriDate:"5 رمضان 1332 هـ",location:"أوروبا الوسطى والبلقان",description:"بعد رفض صربيا لبعض شروط الإنذار النمساوي، أعلنت الإمبراطورية النمساوية المجرية الحرب عليها. وبدأت روسيا (حليفة صربيا) بالتعبئة العامة لجيوشها.",strategicSignificance:"تفعيل نظام \"التحالفات المتشابكة\" في أوروبا، مما جرّ دولاً أخرى إلى ساحة المعركة تباعاً."},
  {id:"e3",orderIndex:3,category:"الحرب العالمية الأولى",title:"تفعيل \"خطة شليفن\" وغزو بلجيكا",gregorianDate:"4 أغسطس 1914 م",hijriDate:"12 رمضان 1332 هـ",location:"بلجيكا وفرنسا",description:"أعلنت ألمانيا الحرب على روسيا وفرنسا. ولتجنب القتال على جبهتين، نفذت ألمانيا خطة لتوجيه ضربة سريعة لفرنسا عبر غزو بلجيكا (المحايدة) للوصول إلى باريس.",strategicSignificance:"أدى غزو بلجيكا إلى دفع بريطانيا لإعلان الحرب على ألمانيا فوراً، لتكتمل بذلك أطراف النزاع الرئيسية."},
  {id:"e4",orderIndex:4,category:"الحرب العالمية الأولى",title:"معركة المارن الأولى (وقف التقدم الألماني)",gregorianDate:"6 - 12 سبتمبر 1914 م",hijriDate:"16 - 22 شوال 1332 هـ",location:"حوض نهر المارن، فرنسا",description:"شنت القوات الفرنسية والبريطانية هجوماً مضاداً حاسماً ضد الجيش الألماني الذي كان يزحف بسرعة نحو العاصمة باريس، ونجحت في إيقاف تقدمه وإجباره على التراجع.",strategicSignificance:"فشل خطة \"شليفن\" الألمانية في تحقيق نصر سريع، وبداية تأسيس نظام \"حرب الخنادق\" الذي جمّد الجبهة الغربية لسنوات."},
  {id:"e5",orderIndex:5,category:"الحرب العالمية الأولى",title:"بدء \"حرب الخنادق\" وإنشاء الأنظمة الدفاعية المعقدة",gregorianDate:"خريف 1914 م",hijriDate:"أواخر 1332 هـ",location:"الجبهة الغربية (من ساحل القنال الإنجليزي حتى سويسرا)",description:"بعد فشل \"الحرب المتنقلة\" السريعة لكلا الطرفين، حفرت الجيوش الخنادق للاحتماء، فتحولت الأرض إلى شبكات معقدة من الخنادق المتوازية والمتقاطعة المدعمة بالأسلاك الشائكة والمخابئ العميقة المقاومة للمدفعية، تفصل بينها منطقة عازلة مميتة تُعرف بـ \"الأرض المحايدة\".",strategicSignificance:"أدى هذا التطور إلى تجميد خطوط القتال لسنوات وإلغاء فاعلية الهجمات التقليدية، مما أجبر الجيوش على البحث عن تكتيكات وأسلحة جديدة (كالغازات والدبابات والمدافع الرشاشة والخفيفة وقاذفات اللهب) لكسر هذا الجمود الذي استنزف طاقات الدول."},
  {id:"e6",orderIndex:6,category:"الحرب العالمية الأولى",title:"دخول الدولة العثمانية الحرب العالمية الأولى",gregorianDate:"29 أكتوبر 1914 م",hijriDate:"9 ذو الحجة 1332 هـ",location:"البحر الأسود والجبهات الشرقية",description:"قامت سفن حربية عثمانية (تحت قيادة ألمانية) بقصف موانئ روسية على سواحل البحر الأسود، مما أدخل الدولة العثمانية الحرب رسمياً إلى جانب ألمانيا والنمسا (دول المركز).",strategicSignificance:"إعلان روسيا وبريطانيا وفرنسا الحرب على الدولة العثمانية، مما وسّع نطاق الحرب لتشمل الشرق الأوسط وشمال أفريقيا، وفتح جبهات قتال جديدة."},
  {id:"e7",orderIndex:7,category:"الحرب العالمية الأولى",title:"تنظيم معسكرات التدريب العسكري المكثف",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الدول المتحاربة",description:"مع اندلاع الحرب وتدفق ملايين المتطوعين والمجندين الجدد، أنشأت الجيوش معسكرات تدريب ضخمة لتحويل المدنيين إلى جنود في أسابيع قليلة. شمل التدريب استخدام الأسلحة، والتحركات التكتيكية، والتكيف مع ظروف حرب الخنادق.",strategicSignificance:"شكّلت هذه المعسكرات العمود الفقري لبناء الجيوش الجماهيرية الحديثة، وأظهرت قدرة الدول الصناعية على تعبئة وتسليح أعداد غير مسبوقة من المقاتلين في زمن قياسي."},
  {id:"e8",orderIndex:8,category:"الحرب العالمية الأولى",title:"توحيد المعدات والتجهيزات الفردية للجندي",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع جبهات القتال",description:"فرضت الحرب توحيد وتنميط العتاد الفردي للجندي من خوذات فولاذية وأحزمة وحقائب ظهر وأدوات حفر ومطارات مياه وعلب إسعافات أولية، بعد أن كان التجهيز عشوائياً في بداية الحرب.",strategicSignificance:"أدى هذا التوحيد إلى تحسين الكفاءة اللوجستية وتقليل الخسائر، وأسس لمفهوم \"المعدات القياسية\" الذي أصبح ركيزة أساسية في جميع الجيوش الحديثة."},
  {id:"e9",orderIndex:9,category:"الحرب العالمية الأولى",title:"تطبيق نظام \"التناوب\" في الخنادق",gregorianDate:"أواخر 1914 - 1918 م",hijriDate:"أواخر 1332 - 1337 هـ",location:"الجبهة الغربية بشكل رئيسي",description:"لتجنب الانهيار النفسي والجسدي الكامل للجنود، طبقت الجيوش نظام تناوب دوري ينقل الوحدات بين خنادق الخط الأمامي وخنادق الدعم ومناطق الراحة الخلفية كل بضعة أيام أو أسابيع.",strategicSignificance:"ساهم هذا النظام في الحفاظ على الحد الأدنى من الفاعلية القتالية والروح المعنوية، وأصبح نموذجاً تنظيمياً أساسياً في إدارة القوات في الحروب اللاحقة."},
  {id:"e10",orderIndex:10,category:"الحرب العالمية الأولى",title:"تطوير سلسلة الإخلاء الطبي الميداني",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات",description:"طورت الجيوش سلسلة إخلاء طبي متعددة المراحل تبدأ من نقاط الإسعاف الأولي في الخنادق، مروراً بمحطات تضميد متقدمة، وصولاً إلى المستشفيات الميدانية ثم مستشفيات القاعدة الخلفية.",strategicSignificance:"أحدثت هذه المنظومة ثورة في الطب العسكري وأنقذت حياة مئات الآلاف من الجرحى، وأسست للمبادئ الحديثة في طب الطوارئ والإخلاء الميداني المستخدمة حتى اليوم."},
  {id:"e11",orderIndex:11,category:"الحرب العالمية الأولى",title:"فرض الرقابة العسكرية على رسائل الجنود",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات والجبهات الداخلية",description:"فرضت القيادات العسكرية رقابة صارمة على المراسلات بين الجنود وعائلاتهم، حيث كان الضباط يقرأون الرسائل ويشطبون أي معلومات تتعلق بالمواقع أو الخسائر أو الروح المعنوية المنخفضة.",strategicSignificance:"ساهمت هذه الرقابة في حماية الأسرار العسكرية والحفاظ على معنويات الجبهة الداخلية، لكنها في المقابل عمّقت الهوة النفسية بين الجنود وذويهم الذين لم يدركوا حقيقة الأوضاع المأساوية في الخنادق."},
  {id:"e12",orderIndex:12,category:"الحرب العالمية الأولى",title:"نظام الإعاشة وتوزيع الحصص الغذائية الميدانية",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات",description:"واجهت الجيوش تحدي إطعام ملايين الجنود يومياً في ظروف قتالية قاسية. تم تطوير أنظمة معقدة لنقل وتوزيع الحصص الغذائية تشمل الخبز المعلب واللحوم المحفوظة والبسكويت الصلب والشاي، مع تفاوت كبير في الجودة والكمية بين الجيوش.",strategicSignificance:"كشفت الحرب أن الإمداد الغذائي لا يقل أهمية عن الإمداد بالذخيرة، وأن انهيار منظومة الإعاشة يؤدي مباشرة إلى انهيار الروح المعنوية والقدرة القتالية."},
  {id:"e13",orderIndex:13,category:"الحرب العالمية الأولى",title:"الاعتماد على \"العدائين\" (Runners) للاتصالات الميدانية",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات",description:"في ظل تدمير خطوط الهاتف الميداني بالقصف المدفعي المستمر، اعتمدت الجيوش بشكل كبير على جنود مخصصين يُعرفون بـ \"العدائين\" لنقل الرسائل والأوامر يدوياً بين مواقع القيادة والخنادق الأمامية تحت النيران.",strategicSignificance:"كشفت هذه الممارسة عن الفجوة التكنولوجية الخطيرة في مجال الاتصالات العسكرية، وكانت مهمة العدائين من أخطر المهام حيث تعرض كثير منهم للقتل أو الإصابة، مما حفز تطوير وسائل اتصال أكثر موثوقية."},
  {id:"e14",orderIndex:14,category:"الحرب العالمية الأولى",title:"تعبئة الأطفال والمدارس في المجهود الحربي",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الدول المتحاربة",description:"لم تقتصر التعبئة على البالغين، بل شملت الأطفال والمراهقين عبر المدارس والكشافة. شارك الأطفال في جمع المعادن والمواد القابلة لإعادة التدوير، وحياكة الجوارب للجنود، وجمع التبرعات، بل وتم تجنيد بعض القاصرين بأعمار مزيفة.",strategicSignificance:"كشفت هذه التعبئة الشاملة عن مدى تغلغل الحرب في كل طبقات المجتمع، وأثرت بشكل عميق على جيل كامل نشأ في ظل ثقافة الحرب والتضحية."},
  {id:"e15",orderIndex:15,category:"الحرب العالمية الأولى",title:"نشوء التجارة والأسواق السوداء في الخنادق",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"الخنادق وخطوط الإمداد الخلفية",description:"نشأ في الخنادق اقتصاد موازٍ غير رسمي يعتمد على المقايضة والتجارة بين الجنود. تحولت سلع مثل السجائر والشوكولاتة والصابون إلى عملات بديلة، كما ازدهرت الأسواق السوداء في المناطق الخلفية.",strategicSignificance:"أظهرت هذه الظاهرة قدرة الإنسان على خلق أنظمة اقتصادية بديلة حتى في أقسى الظروف، كما كشفت عن أوجه القصور في أنظمة التموين الرسمية."},
  {id:"e16",orderIndex:16,category:"الحرب العالمية الأولى",title:"تجنيد قوات المستعمرات والأقليات",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"المستعمرات الأوروبية في أفريقيا وآسيا والأمريكتين",description:"لجأت الإمبراطوريات الاستعمارية (بريطانيا وفرنسا بشكل خاص) إلى تجنيد مئات الآلاف من رعايا مستعمراتها في أفريقيا والهند وجنوب شرق آسيا والكاريبي للقتال والعمل في الخطوط الخلفية.",strategicSignificance:"ساهم هذا التجنيد في سد النقص البشري الحاد، لكنه في المقابل أوجد وعياً سياسياً جديداً بين شعوب المستعمرات التي طالبت لاحقاً بحقوقها واستقلالها مقابل تضحياتها الكبرى."},
  {id:"e17",orderIndex:17,category:"الحرب العالمية الأولى",title:"تطبيق عقوبات الإعدام الميدانية والانضباط العسكري",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات",description:"طبقت الجيوش المتحاربة عقوبات صارمة للحفاظ على الانضباط، شملت الإعدام رمياً بالرصاص بتهم الجبن أمام العدو والفرار من الخدمة والتمرد. أُعدم مئات الجنود من مختلف الجيوش بأحكام عسكرية سريعة.",strategicSignificance:"أثارت هذه الإعدامات جدلاً أخلاقياً واسعاً استمر لعقود بعد الحرب، خاصة بعد اكتشاف أن كثيراً من المُعدَمين كانوا يعانون من \"صدمة القذيفة\" وليس الجبن، مما أدى لاحقاً إلى مراجعات قانونية وتشريعات لإعادة الاعتبار لهم."},
  {id:"e18",orderIndex:18,category:"الحرب العالمية الأولى",title:"التعبئة الروحية ودور القساوسة العسكريين",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الجبهات",description:"لعب رجال الدين من مختلف الطوائف دوراً محورياً في الخنادق، حيث قدموا الدعم الروحي والنفسي للجنود، وأقاموا الصلوات الجماعية، ورافقوا المحتضرين في لحظاتهم الأخيرة، بل وشارك بعضهم في إجلاء الجرحى تحت النار.",strategicSignificance:"كشفت الحرب عن الحاجة الماسة للدعم الروحي في ظروف القتال القاسية، وأسست لمفهوم \"القسيس العسكري\" كعنصر مؤسسي دائم في الجيوش الحديثة، رغم أن الحرب ذاتها أدت إلى أزمة إيمانية عميقة لدى كثير من الجنود."},
  {id:"e19",orderIndex:19,category:"الحرب العالمية الأولى",title:"انتشار \"الخرافات\" والنزعة القدرية بين الجنود",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"جميع الخنادق والجبهات",description:"في مواجهة الموت العشوائي والقصف المستمر، لجأ الجنود إلى التمائم والطقوس الخرافية وحمل \"أشياء الحظ\" كوسيلة نفسية للتعامل مع الخوف. انتشرت أيضاً نزعة قدرية عميقة مفادها أن \"القذيفة التي تحمل اسمك لا مفر منها\".",strategicSignificance:"عكست هذه الظاهرة الأثر النفسي المدمر لحرب الخنادق على العقل البشري، وأصبحت مادة غنية للدراسات النفسية والأنثروبولوجية لاحقاً حول سلوك الإنسان تحت الضغط الشديد والمستمر."},
  {id:"e20",orderIndex:20,category:"الحرب العالمية الأولى",title:"انتشار وباء \"قدم الخندق\" (Trench Foot)",gregorianDate:"شتاء 1914 - 1915 م",hijriDate:"أواخر 1332 - 1333 هـ",location:"خنادق الجبهة الغربية (خاصة في فلاندرز وفرنسا)",description:"بسبب الوقوف الطويل والمستمر للجنود في خنادق مغمورة بالمياه المتجمدة والطين، وعدم قدرتهم على تجفيف أقدامهم أو تبديل جواربهم لأيام، أصيب عشرات الآلاف بتعفن الأنسجة الموضعي وموتها (الغرغرينا).",strategicSignificance:"أدى هذا الوباء إلى خروج أعداد ضخمة من الجنود من الخدمة وعمليات بتر واسعة للأطراف. أُجبرت الجيوش على تغيير روتين الحياة اليومية عبر فرض تفتيش يومي وصارم على أقدام الجنود، وتوزيع \"شحم الحيتان\" لدهن الأقدام كعازل للرطوبة، مما أضاف عبئاً لوجستياً جديداً."},
  {id:"e21",orderIndex:21,category:"الحرب العالمية الأولى",title:"هدنة \"عيد الميلاد\" غير الرسمية بين الجنود",gregorianDate:"25 ديسمبر 1914 م",hijriDate:"7 صفر 1333 هـ",location:"\"الأرض المحايدة\" بين الخنادق المتقابلة على الجبهة الغربية",description:"في ظاهرة استثنائية، اتفق الجنود البريطانيون والألمان بشكل عفوي على وقف إطلاق النار، وخرجوا من خنادقهم ليتقابلوا في المنطقة المحايدة لتبادل التحيات، ودفن الموتى سوياً، ومقايضة الأطعمة، بل ولعبوا كرة القدم معاً.",strategicSignificance:"رغم أنها لم تؤثر على المسار العسكري للحرب واستمرت القيادات في التحذير منها، إلا أنها كشفت عن تطوير الجنود في الخنادق لـ \"قيود على العنف\" ومبدأ \"عش ودع الآخرين يعيشون\"، مما أظهر العبء النفسي الهائل لحرب الخنادق والانفصال بين الجنود والقيادات العليا."},
  {id:"e22",orderIndex:22,category:"الحرب العالمية الأولى",title:"انتشار وباء التيفوس في معسكرات الأسرى",gregorianDate:"فبراير 1915 م",hijriDate:"ربيع الآخر 1333 هـ",location:"معسكرات أسرى الحرب في ألمانيا",description:"تفشى وباء التيفوس القاتل بين أسرى الحرب من قوات الحلفاء المحتجزين في المعسكرات الألمانية، وذلك بسبب الاكتظاظ الشديد وانعدام مقومات النظافة الأساسية.",strategicSignificance:"سلط هذا الوباء الضوء على الظروف المأساوية لأسرى الحرب، وأجبر السلطات الألمانية على تحسين إجراءات الحجر الصحي وتطوير آليات التطهير لتجنب انتقال الوباء إلى السكان المدنيين وقوات الحراسة."},
  {id:"e23",orderIndex:23,category:"الحرب العالمية الأولى",title:"حملة جاليبولي (معارك مضيق الدردنيل)",gregorianDate:"19 فبراير 1915 م (بداية الحملة)",hijriDate:"5 ربيع الآخر 1333 هـ",location:"شبه جزيرة جاليبولي (الدولة العثمانية)",description:"شنت بريطانيا وفرنسا هجوماً بحرياً وبرياً ضخماً للسيطرة على مضيق الدردنيل بهدف احتلال العاصمة العثمانية (إسطنبول) وفتح طريق إمداد بحري آمن إلى روسيا.",strategicSignificance:"صمود عثماني قوي وانتصار دفاعي كبير، أدى في النهاية إلى انسحاب قوات الحلفاء بعد أشهر من القتال الدامي وتكبدهم خسائر فادحة."},
  {id:"e24",orderIndex:24,category:"الحرب العالمية الأولى",title:"ظهور حالات \"صدمة القذيفة\" (Shell Shock)",gregorianDate:"برزت بشكل متزايد منذ عام 1915 م",hijriDate:"1333 هـ وما بعدها",location:"الجبهة الغربية ومصحات العواصم الأوروبية",description:"مع تعرض الجنود لقصف مدفعي ثقيل ومتواصل لأيام وأسابيع، بدأت تظهر حالات انهيار عصبي ونفسي حاد بين المقاتلين. شملت الأعراض الارتجاف المستمر، الشلل، فقدان النطق، والعمى المؤقت دون وجود أي إصابة جسدية مباشرة.",strategicSignificance:"شكّلت هذه الحالة تحدياً هائلاً للقيادات العسكرية التي اعتبرت المصابين في البداية مجرد \"جبناء\" أو متمردين. لكن مع تزايد الأعداد بشكل يهدد قوام الجيوش، اضطرت المؤسسات الطبية للاعتراف بالصدمات النفسية كإصابات حرب حقيقية، مما شكل البداية الفعلية لعلم الطب النفسي العسكري الحديث."},
  {id:"e25",orderIndex:25,category:"الحرب العالمية الأولى",title:"الهجوم الألماني الأول بالغاز السام (معركة إيبر الثانية)",gregorianDate:"22 أبريل 1915 م",hijriDate:"8 جمادى الآخرة 1333 هـ",location:"مدينة إيبر (Ypres)، بلجيكا",description:"في محاولة لكسر جمود حرب الخنادق، استخدم الجيش الألماني الغاز السام ضد خطوط الحلفاء.",strategicSignificance:"أطلق هذا الهجوم شرارة سباق التسلح الكيميائي المحموم بين الدول المتحاربة، مما أضاف أسلحة محملة بالغازات إلى ساحات المعارك، وفرض على الجيوش تطوير وسائل وقاية كأقنعة الغاز."},
  {id:"e26",orderIndex:26,category:"الحرب العالمية الأولى",title:"إدخال سلاح \"قاذف اللهب\" إلى ساحات المعارك",gregorianDate:"عام 1915 م",hijriDate:"1333 هـ",location:"ساحات القتال القريب على الجبهة الغربية",description:"أدخل الجيش الألماني قاذفات اللهب المحمولة كأداة قتالية جديدة. كان السلاح يتطلب فريقاً من جنديين لتشغيله، واستُخدم لتمهيد الطريق أمام وحدات المشاة الهجومية عن طريق إطلاق النيران داخل خنادق العدو ومخابئه من مسافات قريبة.",strategicSignificance:"أضاف هذا السلاح بُعداً نفسياً مرعباً لحرب الخنادق وبث الذعر المباشر في صفوف المدافعين. ورغم محدودية مداه التكتيكي، إلا أنه ساهم في تطوير أساليب \"قوات الصدمة\" لاقتحام التحصينات، وسرعان ما تبنت الجيوش الأخرى أسلحة مشابهة."},
  {id:"e27",orderIndex:27,category:"الحرب العالمية الأولى",title:"تكثيف دوريات الليل وغارات الخنادق",gregorianDate:"1915 - 1918 م",hijriDate:"1333 - 1337 هـ",location:"الجبهة الغربية والجبهات الأخرى",description:"تطورت عمليات الدوريات الليلية وغارات الخنادق لتصبح نشاطاً يومياً روتينياً. كانت مجموعات صغيرة من الجنود تتسلل ليلاً عبر \"الأرض المحايدة\" لاستطلاع مواقع العدو، وأسر جنود للاستجواب، وتدمير نقاط المراقبة والأسلاك الشائكة.",strategicSignificance:"شكلت هذه العمليات عبئاً نفسياً هائلاً على الجنود بسبب خطورتها الشديدة وطبيعتها القتالية القريبة، لكنها كانت ضرورية للحصول على المعلومات الاستخبارية والحفاظ على الروح الهجومية."},
  {id:"e28",orderIndex:28,category:"الحرب العالمية الأولى",title:"انخراط النساء في العمل بمصانع الذخيرة (\"فتيات الكناري\")",gregorianDate:"1915 - 1918 م",hijriDate:"1333 - 1337 هـ",location:"بريطانيا وفرنسا وألمانيا",description:"مع ذهاب الرجال إلى الجبهات، التحقت مئات الآلاف من النساء بمصانع الذخيرة والمتفجرات. لُقبت العاملات بـ \"فتيات الكناري\" لأن التعرض المستمر لمادة TNT حوّل بشرتهن إلى اللون الأصفر وتسبب في أمراض خطيرة.",strategicSignificance:"كشفت هذه الظاهرة عن الثمن الصحي الباهظ الذي دفعته النساء في المجهود الحربي، وساهمت بشكل حاسم في تغيير النظرة المجتمعية لقدرات المرأة ودعم مطالبها بالمساواة وحق التصويت."},
  {id:"e29",orderIndex:29,category:"الحرب العالمية الأولى",title:"الإجازات القصيرة وعقدة الانفصال عن الجبهة الداخلية",gregorianDate:"1915 - 1918 م",hijriDate:"1333 - 1337 هـ",location:"الجبهات الأمامية والجبهات الداخلية",description:"حصل الجنود على إجازات قصيرة ونادرة للعودة إلى ديارهم، لكن كثيراً منهم وجدوا أنفسهم غير قادرين على التواصل مع عائلاتهم التي لا تدرك حقيقة الأوضاع في الخنادق. شعر كثيرون بالاغتراب في بيوتهم وبالرغبة في العودة إلى رفاقهم.",strategicSignificance:"كشفت هذه الظاهرة عن الهوة النفسية العميقة التي خلقتها الحرب بين المقاتلين والمدنيين، وهي ظاهرة أصبحت لاحقاً محوراً أساسياً في دراسات اضطراب ما بعد الصدمة."},
  {id:"e30",orderIndex:30,category:"الحرب العالمية الأولى",title:"ابتكار وتطوير أقنعة الغاز الميدانية",gregorianDate:"1915 - 1918 م",hijriDate:"1333 - 1337 هـ",location:"جميع الجبهات",description:"بعد الهجمات الكيميائية الأولى، تسابقت الجيوش لتطوير أقنعة واقية من الغاز. تطورت من قطع قماش مبللة بالماء أو البول في البداية، إلى أقنعة متطورة بفلاتر كيميائية تغطي الوجه بالكامل وتُوزع على كل جندي كجزء أساسي من عتاده.",strategicSignificance:"أصبح قناع الغاز رمزاً بصرياً مميزاً للحرب العالمية الأولى، وأدى تطويره المستمر إلى سباق تسلح كيميائي-دفاعي متوازٍ، كما أسس لمبادئ الحماية من أسلحة الدمار الشامل."},
  {id:"e31",orderIndex:31,category:"الحرب العالمية الأولى",title:"ظهور \"فن الخنادق\" (Trench Art)",gregorianDate:"1915 - 1918 م",hijriDate:"1333 - 1337 هـ",location:"جميع الخنادق على مختلف الجبهات",description:"حوّل الجنود خلال فترات الانتظار الطويلة في الخنادق مخلفات الحرب (كأغلفة القذائف النحاسية وشظايا المعادن) إلى أعمال فنية وحرفية مثل المزهريات المنقوشة والولاعات والخواتم والصلبان التذكارية.",strategicSignificance:"شكّل \"فن الخنادق\" وسيلة نفسية للتعامل مع الملل والخوف والصدمة، وأصبح لاحقاً مصدراً تاريخياً وأثرياً فريداً يوثق التجربة الإنسانية للجنود في الحرب."},
  {id:"e32",orderIndex:32,category:"الحرب العالمية الأولى",title:"إعدام الممرضة إديث كافيل",gregorianDate:"12 أكتوبر 1915 م",hijriDate:"ذو الحجة 1333 هـ",location:"بروكسل، بلجيكا (تحت الاحتلال الألماني)",description:"قامت السلطات العسكرية الألمانية بإعدام الممرضة البريطانية إديث كافيل رمياً بالرصاص بتهمة مساعدة جنود الحلفاء على الهروب من بلجيكا المحتلة إلى هولندا المحايدة.",strategicSignificance:"أثار إعدامها موجة غضب عارمة عالمياً، واستُخدمت قصتها كأداة دعاية (بروباغاندا) قوية جداً من قبل الحلفاء لتصوير القسوة الألمانية، مما ساهم في زيادة معدلات التجنيد في بريطانيا وتأليب الرأي العام، خاصة في الولايات المتحدة."},
  {id:"e33",orderIndex:33,category:"الحرب العالمية الأولى",title:"تطور سلاح الطيران والقتال الجوي",gregorianDate:"1915 - 1916 م",hijriDate:"1333 - 1334 هـ",location:"سماء الجبهة الغربية",description:"بعد أن اقتصر دور الطائرات في البداية على مهام الاستطلاع وتصوير الخنادق، تم ابتكار آلية (ألمانية المنشأ) لربط المدافع الرشاشة بحيث تطلق النار من خلال مروحة الطائرة دون تدميرها. أدى ذلك إلى ظهور \"الطائرات المقاتلة\" وبداية المبارزات الجوية المباشرة بين الطيارين.",strategicSignificance:"نقل هذا التطور التكنولوجي ساحة المعركة إلى الجو بشكل فعلي. وأسس لمفهوم \"السيادة الجوية\" كعنصر تكتيكي لا غنى عنه لدعم القوات البرية وتوجيه المدفعية، وهو المفهوم الذي سيطر على العقيدة العسكرية طوال القرن العشرين."},
  {id:"e34",orderIndex:34,category:"الحرب العالمية الأولى",title:"معركة فردان (أطول معارك الحرب)",gregorianDate:"21 فبراير - 18 ديسمبر 1916 م",hijriDate:"17 ربيع الآخر - 23 صفر 1335 هـ",location:"مدينة فردان، الجبهة الغربية (شمال شرق فرنسا)",description:"شنت القيادة الألمانية هجوماً مدفعياً وبرياً مكثفاً ومستمراً على سلسلة الحصون الفرنسية المحيطة بمدينة فردان، بهدف دفع الجيش الفرنسي إلى نقطة الانهيار عبر \"استنزاف دمائه\". اتسمت المعركة بوحشية غير مسبوقة وتحولت إلى حرب خنادق واستنزاف طاحنة استمرت لما يقارب العشرة أشهر.",strategicSignificance:"رغم الخسائر البشرية المرعبة للطرفين، فشلت ألمانيا في تحقيق هدفها باختراق الجبهة أو إسقاط فرنسا. أصبحت فردان رمزاً للصلابة الدفاعية، ولكنها استنزفت الموارد العسكرية الألمانية بشكل خطير، وأضعفت قدرتها المستقبلية على المبادرة بالهجوم."},
  {id:"e35",orderIndex:35,category:"الحرب العالمية الأولى",title:"ثورة \"عيد الفصح\" واستغلال الحرب داخلياً",gregorianDate:"أبريل 1916 م",hijriDate:"جمادى الآخرة 1334 هـ",location:"دبلن، أيرلندا",description:"استغل القوميون الأيرلنديون انشغال بريطانيا بالحرب العالمية لشن انتفاضة مسلحة في دبلن للمطالبة بالاستقلال. قُمعت الثورة بعنف خلال أسبوع، لكن إعدام قادتها أثار تعاطفاً شعبياً واسعاً.",strategicSignificance:"كشفت هذه الثورة عن هشاشة الجبهات الداخلية للإمبراطوريات المتحاربة، وأظهرت كيف يمكن للحرب الخارجية أن تُشعل فتيل الحركات الانفصالية والقومية الداخلية، مما مهد لاستقلال أيرلندا لاحقاً."},
  {id:"e36",orderIndex:36,category:"الحرب العالمية الأولى",title:"تطبيق \"التوقيت الصيفي\" لأول مرة",gregorianDate:"30 أبريل 1916 م",hijriDate:"جمادى الآخرة 1334 هـ",location:"ألمانيا والإمبراطورية النمساوية المجرية",description:"كإجراء طارئ في زمن الحرب، قامت الإمبراطورية الألمانية وحلفاؤها بتقديم عقارب الساعة لمدة ساعة واحدة لتقليل استخدام الإضاءة الاصطناعية وتوفير الفحم الحرج للمجهود الحربي.",strategicSignificance:"سرعان ما تبنت بريطانيا وفرنسا ودول أخرى نفس النظام. يعكس هذا الحدث مدى تغلغل متطلبات الحرب في تنظيم الحياة اليومية للمدنيين وتغيير الوقت نفسه، وهو نظام استمر تأثيره عالمياً حتى يومنا هذا."},
  {id:"e37",orderIndex:37,category:"الحرب العالمية الأولى",title:"تشريع نظام التجنيد الإجباري في بريطانيا",gregorianDate:"17 مايو 1916 م",hijriDate:"14 رجب 1334 هـ (تقريباً)",location:"بريطانيا العظمى",description:"بعد أن كان الجيش البريطاني يعتمد كلياً على المتطوعين، وأمام تدفق المجندين غير الكافي لسد النقص الحاد، أقرت الحكومة البريطانية نظام التجنيد الإجباري لضمان توفير الجنود للقوات المسلحة.",strategicSignificance:"مثّل هذا تحولاً جذرياً سمح لبريطانيا بتكوين جيش موسع قادر على خوض حرب استنزاف طويلة الأمد ضد ألمانيا على الجبهة الغربية، وتعويض الخسائر الفادحة في المعارك الكبرى مثل معركة \"السوم\"."},
  {id:"e38",orderIndex:38,category:"الحرب العالمية الأولى",title:"هجوم بروسيلوف",gregorianDate:"4 يونيو - 20 سبتمبر 1916 م",hijriDate:"شعبان - ذو الحجة 1334 هـ",location:"الجبهة الشرقية (أوكرانيا الحالية)",description:"شن الجيش الإمبراطوري الروسي، بقيادة الجنرال ألكسي بروسيلوف، هجوماً كاسحاً ومبتكراً ضد قوات النمسا والمجر، محققاً تقدماً كبيراً وأسراً لمئات الآلاف من الجنود.",strategicSignificance:"كان هذا الهجوم هو الانتصار الروسي الأكبر في الحرب، وأجبر ألمانيا على سحب قوات من جبهة فردان (في الغرب) لإنقاذ حليفتها المنهارة، مما خفف الضغط عن الفرنسيين. لكنه في المقابل استنزف الموارد الروسية بشكل فادح ومهد للانهيار الداخلي لجيشها لاحقاً."},
  {id:"e39",orderIndex:39,category:"الحرب العالمية الأولى",title:"انطلاق الثورة العربية الكبرى",gregorianDate:"10 يونيو 1916 م",hijriDate:"9 شعبان 1334 هـ",location:"الحجاز وامتدت إلى بلاد الشام",description:"أعلن الشريف حسين بن علي الثورة المسلحة ضد الدولة العثمانية بدعم وتنسيق عسكري ولوجستي من بريطانيا. شملت العمليات العسكرية السيطرة على مكة، وتنفيذ حرب عصابات لتعطيل خط سكة حديد الحجاز، ومهاجمة الحاميات العسكرية العثمانية.",strategicSignificance:"نجحت في تشتيت جزء كبير من القوات العثمانية وإلزامها بالبقاء في الحجاز والشام لحماية خطوط الإمداد، مما خفف الضغط عن القوات البريطانية وسهّل تقدمها لاحقاً في فلسطين وسوريا، وشكلت بداية لتغيير الخارطة السياسية للشرق الأوسط."},
  {id:"e40",orderIndex:40,category:"الحرب العالمية الأولى",title:"معركة السوم (ظهور الدبابات الأول)",gregorianDate:"1 يوليو - 18 نوفمبر 1916 م",hijriDate:"1 شعبان - 22 محرم 1335 هـ",location:"حوض نهر السوم، شمال فرنسا",description:"نفذت القوات البريطانية والفرنسية هجوماً واسع النطاق ضد الخطوط الألمانية لتخفيف الضغط الخانق عن جبهة فردان. شهد اليوم الأول من المعركة أكبر خسارة في تاريخ الجيش البريطاني، وفي هذه المعركة تم إدخال سلاح \"الدبابة\" لأول مرة في التاريخ العسكري لكسر جمود الخنادق.",strategicSignificance:"أثبتت المعركة أن قوات الحلفاء قادرة على تحمل حرب استنزاف طويلة الأمد. ورغم التقدم الجغرافي المحدود، أجبرت هذه المعركة الجيش الألماني لاحقاً على التراجع التكتيكي وإعادة التموضع، وبدأت موازين القوى تميل تدريجياً لصالح الحلفاء بفضل التفوق العددي والصناعي."},
  {id:"e41",orderIndex:41,category:"الحرب العالمية الأولى",title:"إدخال \"جبيرة توماس\" لعلاج كسور الفخذ",gregorianDate:"1916 - 1918 م",hijriDate:"1334 - 1337 هـ",location:"المستشفيات الميدانية ومحطات الإسعاف",description:"تم تبني \"جبيرة توماس\" على نطاق واسع في الجبهة الغربية لتثبيت كسور عظم الفخذ أثناء نقل الجرحى. قبل استخدامها كانت نسبة الوفيات من كسور الفخذ المركبة تصل إلى 80%، وبعد تعميمها انخفضت بشكل كبير.",strategicSignificance:"شكّلت هذه الأداة البسيطة ثورة في الطب الميداني وأنقذت آلاف الأرواح، وأثبتت أن الابتكارات الطبية الصغيرة يمكن أن يكون لها أثر استراتيجي ضخم على القدرة البشرية للجيوش."},
  {id:"e42",orderIndex:42,category:"الحرب العالمية الأولى",title:"تطور أساليب العلاج لضحايا \"صدمة القذيفة\"",gregorianDate:"1916 - 1918 م",hijriDate:"1334 - 1337 هـ",location:"المصحات والمستشفيات العسكرية في بريطانيا وفرنسا",description:"مع تزايد حالات الانهيار النفسي، طور الأطباء أساليب علاجية متنوعة تراوحت بين العلاج بالكلام والتنويم المغناطيسي والعلاج بالعمل، إلى أساليب قسرية مثيرة للجدل كالصدمات الكهربائية.",strategicSignificance:"مثّلت هذه المحاولات البداية الفعلية للطب النفسي العسكري المنهجي، ورغم قسوة بعض الأساليب، إلا أنها أسست لفهم أعمق للصدمات النفسية وأثرها على المقاتلين."},
  {id:"e43",orderIndex:43,category:"الحرب العالمية الأولى",title:"توظيف \"فناني ومصوري الحرب\" الرسميين",gregorianDate:"1916 - 1918 م",hijriDate:"1334 - 1337 هـ",location:"الجبهات المختلفة والمقرات العسكرية",description:"عيّنت الحكومات فنانين ومصورين رسميين لتوثيق الحرب بصرياً. أُرسلوا إلى الجبهات لرسم المعارك والحياة اليومية في الخنادق والتقاط الصور الفوتوغرافية والسينمائية، تحت رقابة عسكرية صارمة.",strategicSignificance:"أنتج هؤلاء الفنانون والمصورون أرشيفاً بصرياً لا يُقدر بثمن، وأسسوا لمفهوم \"التوثيق الرسمي للحرب\" الذي أصبح معياراً في جميع النزاعات اللاحقة."},
  {id:"e44",orderIndex:44,category:"الحرب العالمية الأولى",title:"تفاقم ظاهرة \"جنوح الأحداث\" وتفكك الرقابة الأسرية",gregorianDate:"1914 - 1918 م",hijriDate:"1332 - 1337 هـ",location:"الجبهات الداخلية في جميع الدول المتحاربة",description:"مع غياب الآباء في الجبهات وانشغال الأمهات في المصانع، ارتفعت معدلات جنوح الأحداث والتسرب المدرسي بشكل ملحوظ. لجأ كثير من الأطفال والمراهقين إلى السرقة والتشرد، وتفككت البنية الأسرية التقليدية.",strategicSignificance:"كشفت هذه الظاهرة عن التكلفة الاجتماعية الخفية للحرب الشاملة على الأجيال الناشئة، وأدت لاحقاً إلى تطوير سياسات رعاية الطفولة والأحداث في فترة ما بعد الحرب."},
  {id:"e45",orderIndex:45,category:"الحرب العالمية الأولى",title:"الترحيل القسري للعمالة المدنية البلجيكية",gregorianDate:"أكتوبر 1916 م",hijriDate:"ذو الحجة 1334 هـ / محرم 1335 هـ",location:"بلجيكا المحتلة وألمانيا",description:"بدأت السلطات الألمانية بحملات ترحيل قسرية واسعة النطاق للمدنيين البلجيكيين لإجبارهم على العمل في المصانع ومناجم الفحم الألمانية لسد النقص الحاد في الأيدي العاملة بسبب التجنيد.",strategicSignificance:"أثار هذا الإجراء تنديداً دولياً واسعاً وعزز من الدعاية المضادة لألمانيا، كما أظهر المدى الذي وصلت إليه القيادة الألمانية لاستنزاف موارد الدول المحتلة لدعم اقتصاد حربها المنهك."},
  {id:"e46",orderIndex:46,category:"الحرب العالمية الأولى",title:"مأسسة الدعاية (البروباغاندا) والرقابة",gregorianDate:"1916 - 1917 م",hijriDate:"1334 - 1335 هـ",location:"الجبهات الداخلية (لندن، برلين، باريس، واشنطن)",description:"أدركت الحكومات المتحاربة خطورة تدفق المعلومات السلبية، فأسست أجهزة صارمة لفرض الرقابة على رسائل الجنود والصحف اليومية. في المقابل، أُطلقت حملات دعاية نفسية مكثفة (عبر الملصقات، والأفلام، والخطابات) لشيطنة العدو، وتبرير التضحيات، وجمع التبرعات لشراء \"سندات الحرب\".",strategicSignificance:"أثبتت هذه الإجراءات أن السيطرة على \"عقول المدنيين\" وحشد الرأي العام لا يقل أهمية عن تسليح الجنود. لقد كرّست الحرب العالمية الأولى استخدام الحرب النفسية كسلاح استراتيجي للحفاظ على استقرار الجبهة الداخلية ومنع انهيارها تحت وطأة الخسائر."},
  {id:"e47",orderIndex:47,category:"الحرب العالمية الأولى",title:"مجاعة \"شتاء اللفت\"",gregorianDate:"شتاء 1916 - 1917 م (تحديداً أوائل 1917)",hijriDate:"ربيع الأول - ربيع الآخر 1335 هـ",location:"ألمانيا (الجبهة الداخلية)",description:"بسبب الحصار البحري البريطاني الخانق وفشل محصول البطاطا، عانى السكان المدنيون في ألمانيا من نقص حاد في الغذاء. اضطرت العائلات للاعتماد بشكل شبه كلي على \"اللفت\" (الذي كان يُستخدم سابقاً كعلف للحيوانات) كبديل غذائي، مما أدى إلى انتشار سوء التغذية.",strategicSignificance:"أدى هذا النقص الحاد في الحصص الغذائية إلى تدهور خطير في الروح المعنوية الألمانية على الجبهة الداخلية، وزيادة الإضرابات العمالية، وشكل ضغطاً هائلاً على الحكومة الألمانية لاتخاذ قرارات يائسة مثل استئناف \"حرب الغواصات المفتوحة\" لكسر الحصار."},
  {id:"e48",orderIndex:48,category:"الحرب العالمية الأولى",title:"تأسيس \"جيش الأرض النسائي\"",gregorianDate:"عام 1917 م",hijriDate:"1335 هـ",location:"الجبهة الداخلية في بريطانيا",description:"استجابة لنقص الغذاء الحاد الناجم عن حصار الغواصات الألمانية وغياب العمالة الزراعية (التي ذهبت لجبهات القتال)، تم تأسيس تنظيم لتشجيع وتدريب النساء على العمل الشاق في المزارع وإنتاج المحاصيل.",strategicSignificance:"لعب هذا التنظيم المدني دوراً حيوياً في إنقاذ بريطانيا من خطر المجاعة المحدق، وأسهم في تفكيك النظرة المجتمعية التقليدية لعمل المرأة وقدرتها على تحمل المسؤوليات الاقتصادية الجسيمة."},
  {id:"e49",orderIndex:49,category:"الحرب العالمية الأولى",title:"التحاق النساء رسمياً بالقوات المسلحة",gregorianDate:"مارس 1917 م وما بعده",hijriDate:"جمادى الأولى 1335 هـ",location:"بريطانيا والولايات المتحدة الأمريكية",description:"مع تزايد الخسائر البشرية واستنزاف الرجال في الخنادق، بدأت النساء بالالتحاق رسمياً في الجيش البريطاني ضمن \"قوات الاحتياط النسائية\"، وكذلك التحقن في البحرية الأمريكية كعضوات في الحرس الوطني لتولي مهام الدعم الإداري واللوجستي.",strategicSignificance:"مثّل هذا التطور تغييراً جذرياً في تركيبة الجيوش التي كانت تقتصر على الذكور. أثبتت هذه الخطوة الأهمية القصوى لمساهمة المرأة في المجهود الحربي، وهو ما مهّد الطريق لاحقاً لتغيرات اجتماعية كبرى، أبرزها حصول النساء على حق التصويت في عدة دول بعد الحرب."},
  {id:"e50",orderIndex:50,category:"الحرب العالمية الأولى",title:"دخول الولايات المتحدة الأمريكية الحرب",gregorianDate:"6 أبريل 1917 م",hijriDate:"14 جمادى الآخرة 1335 هـ",location:"واشنطن (صنع القرار) والتأثير على الجبهة الغربية والبحرية",description:"بعد سلسلة من التوترات، أبرزها استئناف ألمانيا لحرب الغواصات المفتوحة (التي استهدفت السفن التجارية الأمريكية) واعتراض المخابرات البريطانية لـ\"برقية زيمرمان\" (التي حاولت فيها ألمانيا تحريض المكسيك لشن حرب ضد أمريكا)، أعلن الرئيس الأمريكي وودرو ويلسون دخول بلاده الحرب ضد الإمبراطورية الألمانية.",strategicSignificance:"يُعد هذا الحدث نقطة التحول الأهم في الحرب؛ إذ وفر التدخل الأمريكي ضخاً هائلاً للقوات البشرية الطازجة، والإمدادات الصناعية، والقدرات المالية للحلفاء في وقت كانوا يعانون فيه من إنهاك شديد، مما رجّح كفة النصر نهائياً وأنهى الآمال الألمانية."},
  {id:"e51",orderIndex:51,category:"الحرب العالمية الأولى",title:"إقرار الولايات المتحدة لقانون \"الخدمة الانتقائية\" (التجنيد الإلزامي)",gregorianDate:"18 مايو 1917 م",hijriDate:"26 رجب 1335 هـ (تقريباً)",location:"الولايات المتحدة الأمريكية",description:"لعدم كفاية الجيش النظامي الصغير (127 ألف مقاتل) والحرس الوطني، ولإعداد قوات ضخمة للقتال في أوروبا، أقرت الحكومة الأمريكية نظام التجنيد الإلزامي عبر قرعة \"اليانصيب\"، ليتم تسجيل ملايين الشبان وتحويلهم في معسكرات تدريب ضخمة إلى جيش مقاتل.",strategicSignificance:"مكّن هذا التشريع الولايات المتحدة من حشد جيش ضخم تجاوز أربعة ملايين رجل (خَدَم أكثر من مليونين منهم في فرنسا). وقد شكّل هذا الضخ الهائل للقوات الطازجة العامل الذي رجح كفة الحلفاء وأجهض الآمال الألمانية، خاصة خلال الهجمات الحاسمة في خريف 1918."},
  {id:"e52",orderIndex:52,category:"الحرب العالمية الأولى",title:"معركة باشيندايل (معركة إيبر الثالثة) ومعاناة الخنادق الطينية",gregorianDate:"31 يوليو - 10 نوفمبر 1917 م",hijriDate:"شوال 1335 هـ - صفر 1336 هـ",location:"فلاندرز، بلجيكا",description:"شن الجيش البريطاني هجوماً ضخماً في منطقة إيبر، لكن الأمطار الغزيرة غير المسبوقة والضربات المدفعية حولت ساحة المعركة إلى مستنقع من الطين العميق. غرق العديد من الجنود والخيول والدبابات في الوحل قبل أن يتمكنوا حتى من الاشتباك مع العدو.",strategicSignificance:"أصبحت هذه المعركة في الذاكرة التاريخية رمزاً لمعاناة الجندي البسيط وللخسائر العبثية في حرب الخنادق؛ حيث تكبد الحلفاء مئات الآلاف من الإصابات والقتلى مقابل تقدم جغرافي ضئيل جداً، مما أثر بشدة على الروح المعنوية."},
  {id:"e53",orderIndex:53,category:"الحرب العالمية الأولى",title:"معركة كابوريتو (الهزيمة الإيطالية الكبرى)",gregorianDate:"24 أكتوبر - 19 نوفمبر 1917 م",hijriDate:"محرم - صفر 1336 هـ",location:"الجبهة الإيطالية (نهر إيسونزو)",description:"شنت القوات الألمانية والنمساوية هجوماً مباغتاً ومدمراً باستخدام تكتيكات تسلل متطورة (قوات العاصفة) والغاز السام، مما أدى إلى انهيار كامل لخطوط الجيش الإيطالي وتراجعه الفوضوي لمسافات طويلة.",strategicSignificance:"كادت هذه الهزيمة الكارثية أن تخرج إيطاليا من الحرب. أدت إلى تغييرات جذرية في القيادة الإيطالية، وأجبرت بريطانيا وفرنسا على إرسال تعزيزات عاجلة لمنع سقوط إيطاليا، مما أدى في النهاية لتأسيس \"المجلس الحربي الأعلى\" للحلفاء لتوحيد القيادة المشتركة."},
  {id:"e54",orderIndex:54,category:"الحرب العالمية الأولى",title:"ابتكار وتطبيق تكتيكات \"قوات العاصفة\" (تكتيكات التسلل)",gregorianDate:"1917 - 1918 م",hijriDate:"1335 - 1337 هـ",location:"الجبهة الغربية والجبهة الإيطالية",description:"طور الجيش الألماني تكتيكات ثورية تعتمد على وحدات صغيرة مدربة تدريباً خاصاً (Sturmtruppen) تتسلل عبر نقاط الضعف في خطوط العدو بدلاً من الهجمات الأمامية الجماعية التقليدية، مستخدمةً قنابل يدوية ورشاشات خفيفة وقاذفات لهب.",strategicSignificance:"أحدثت هذه التكتيكات ثورة في فنون القتال البري وأنهت عقيدة الهجوم الأمامي الانتحاري. أصبحت أساساً لتكتيكات المشاة الحديثة والعمليات الخاصة في جميع الجيوش المعاصرة."},
  {id:"e55",orderIndex:55,category:"الحرب العالمية الأولى",title:"تعاظم قوة وشرعية النقابات العمالية",gregorianDate:"1914 - 1919 م",hijriDate:"1332 - 1338 هـ",location:"جميع الدول الصناعية المتحاربة",description:"مع تحول الاقتصادات إلى اقتصادات حرب واعتماد الدول على الإنتاج الصناعي المكثف، تعاظم دور النقابات العمالية التي أصبحت شريكاً أساسياً للحكومات في تنظيم العمل وضمان استمرار الإنتاج. حصلت النقابات على اعتراف رسمي وحقوق جديدة مقابل تعاونها.",strategicSignificance:"أسست الحرب لعلاقة جديدة بين الدولة والنقابات العمالية، وأدت إلى تحسينات دائمة في شروط العمل وحقوق العمال، مما شكّل أحد التحولات الاجتماعية الكبرى الناتجة عن الحرب."},
  {id:"e56",orderIndex:56,category:"الحرب العالمية الأولى",title:"تأسيس هيئات مقابر الحرب والمقابر الوطنية الموحدة",gregorianDate:"1917 م وما بعده",hijriDate:"1335 هـ وما بعده",location:"فرنسا وبلجيكا والجبهات الأخرى",description:"مع تراكم أعداد القتلى الهائلة، أسست الدول المتحاربة هيئات رسمية (مثل لجنة مقابر الحرب الإمبراطورية البريطانية) لتنظيم دفن الجنود وتسجيل هوياتهم وإنشاء مقابر وطنية موحدة بتصاميم معمارية مميزة.",strategicSignificance:"أسست هذه الهيئات لثقافة \"إحياء ذكرى الحرب\" الحديثة، وأصبحت المقابر العسكرية رموزاً وطنية قوية وأماكن حج وطني تخلّد ذكرى التضحيات وتحافظ على الذاكرة الجماعية."},
  {id:"e57",orderIndex:57,category:"الحرب العالمية الأولى",title:"الثورة البلشفية وخروج روسيا من الحرب (معاهدة بريست ليتوفسك)",gregorianDate:"7 نوفمبر 1917 م (الثورة) - 3 مارس 1918 م (توقيع المعاهدة)",hijriDate:"21 محرم 1336 هـ - 19 جمادى الأولى 1336 هـ",location:"روسيا والجبهة الشرقية",description:"قاد فلاديمير لينين والبلاشفة ثورة أطاحت بالحكومة الروسية. وبسبب الانهيار الداخلي والرفض الشعبي الواسع للحرب، سارعت الحكومة السوفيتية الجديدة لتوقيع معاهدة سلام منفصلة مع ألمانيا (بريست ليتوفسك)، متنازلة بموجبها عن مساحات شاسعة من الأراضي والموارد.",strategicSignificance:"أدى خروج روسيا إلى إغلاق الجبهة الشرقية بالكامل، مما منح ألمانيا فرصة ذهبية لنقل عشرات الفرق العسكرية إلى الجبهة الغربية لشن هجوم حاسم ومحاولة كسب الحرب قبل وصول القوات الأمريكية بأعداد كبيرة."},
  {id:"e58",orderIndex:58,category:"الحرب العالمية الأولى",title:"انفجار هاليفاكس المدمر",gregorianDate:"6 ديسمبر 1917 م",hijriDate:"ربيع الأول 1336 هـ",location:"ميناء هاليفاكس، كندا (الجبهة الداخلية)",description:"اصطدمت سفينة شحن فرنسية محملة بآلاف الأطنان من المتفجرات والمواد الكيميائية المخصصة للحرب بسفينة نرويجية في الميناء، مما أدى إلى اندلاع حريق تلاه أكبر انفجار من صنع الإنسان (قبل اختراع القنبلة الذرية)، ومسح أجزاء كبيرة من المدينة وتسبب في مقتل وإصابة الآلاف.",strategicSignificance:"أبرز هذا الحادث الكارثي المخاطر الهائلة لجهود التعبئة اللوجستية والإنتاج الحربي على الجبهة الداخلية المدنية، وأدى إلى تدمير مركز حيوي وأساسي لإمداد الحلفاء عبر المحيط الأطلسي."},
  {id:"e59",orderIndex:59,category:"الحرب العالمية الأولى",title:"تطبيق نظام \"تقنين الغذاء\" الإلزامي",gregorianDate:"أوائل عام 1918 م",hijriDate:"ربيع الآخر 1336 هـ",location:"بريطانيا (الجبهة الداخلية)",description:"بعد نجاح حرب الغواصات الألمانية في تقليص الإمدادات، وتفادياً لانهيار الجبهة الداخلية بسبب الجوع، فرضت الحكومة البريطانية نظاماً إلزامياً لتقنين وتوزيع السلع الأساسية (مثل السكر، واللحوم، والزبدة) عبر \"بطاقات التموين\" لجميع المواطنين.",strategicSignificance:"ساهم هذا الإجراء الحازم في استقرار الجبهة الداخلية ومنع سوء التغذية (على عكس ما حدث في ألمانيا)، وأكد على دور الدولة في التدخل الشامل للسيطرة على أدق تفاصيل الحياة اليومية للمدنيين لضمان استمرار المجهود الحربي."},
  {id:"e60",orderIndex:60,category:"الحرب العالمية الأولى",title:"هجوم الربيع الألماني (هجوم لودندورف)",gregorianDate:"21 مارس - 18 يوليو 1918 م",hijriDate:"8 جمادى الآخرة - 9 شوال 1336 هـ",location:"الجبهة الغربية (فرنسا وبلجيكا)",description:"شنت القوات الألمانية سلسلة من الهجمات المكثفة والمباغتة مستخدمة تكتيكات \"قوات الصدمة\" لكسر خطوط الحلفاء وإنهاء الحرب. حقق الهجوم في أسابيعه الأولى تقدماً عميقاً وغير مسبوق منذ عام 1914، وكاد أن يفصل بين القوات البريطانية والفرنسية.",strategicSignificance:"رغم النجاح التكتيكي والتقدم الجغرافي، استُنزفت قوات النخبة الألمانية، وتمددت خطوط إمدادها بشكل مفرط أدى لضعفها. شكّل فشل هذا الهجوم في تحقيق نصر استراتيجي قاضٍ نقطة اللاعودة، وبداية النهاية للقدرة الهجومية للإمبراطورية الألمانية."},
  {id:"e61",orderIndex:61,category:"الحرب العالمية الأولى",title:"تأسيس سلاح الجو الملكي (RAF)",gregorianDate:"1 أبريل 1918 م",hijriDate:"جمادى الآخرة 1336 هـ",location:"المملكة المتحدة",description:"تم دمج \"فيلق الطيران الملكي\" (الذي كان تابعاً للجيش) مع \"الخدمة الجوية البحرية الملكية\" لإنشاء سلاح الجو الملكي البريطاني كقوة عسكرية مستقلة تماماً.",strategicSignificance:"مثّل هذا التأسيس اعترافاً رسمياً ونهائياً بالأهمية الاستراتيجية للسيادة الجوية. كانت هذه أول قوة جوية مستقلة في العالم، وأسست للعقيدة العسكرية الحديثة التي تعتمد على القوة الجوية كذراع حاسم ومستقل في الحروب بدلاً من كونها مجرد أداة استطلاع تابعة للمشاة."},
  {id:"e62",orderIndex:62,category:"الحرب العالمية الأولى",title:"تفشي جائحة \"الأنفلونزا الإسبانية\"",gregorianDate:"ربيع عام 1918 م",hijriDate:"رجب - شعبان 1336 هـ",location:"الجبهات العسكرية والمدن على نطاق عالمي",description:"انتشرت سلالة قاتلة من الأنفلونزا كالنار في الهشيم بين الجيوش المتحاربة والمدنيين. سهّلت الخنادق المكتظة، وضعف المناعة بسبب سوء التغذية، وحركة القوات الكثيفة عبر المحيطات، انتقال الفيروس بسرعة غير مسبوقة.",strategicSignificance:"تسببت الجائحة في إضعاف القدرة القتالية للجيوش بشكل حاد واستنزفت الموارد الطبية المنهكة أصلاً. لقد حصدت الجائحة أرواح ملايين البشر (متجاوزةً أعداد من سقطوا في جبهات القتال)، مما سرّع من إنهاك الدول المشاركة وانهيار قدرتها على الاستمرار في الحرب."},
  {id:"e63",orderIndex:63,category:"الحرب العالمية الأولى",title:"معركة أميان (\"اليوم الأسود\" للجيش الألماني)",gregorianDate:"8 أغسطس 1918 م",hijriDate:"ذو القعدة 1336 هـ",location:"أميان، فرنسا (الجبهة الغربية)",description:"شن الحلفاء هجوماً مباغتاً ومنسقاً باستخدام تكتيكات الأسلحة المشتركة المتقدمة (المشاة، وأكثر من 500 دبابة، والتغطية الجوية والمدفعية). انهارت الدفاعات الألمانية بسرعة غير مسبوقة، واستسلم آلاف الجنود الألمان دون مقاومة تذكر، فاقدين الثقة في قيادتهم.",strategicSignificance:"وصف الجنرال الألماني لودندورف هذا اليوم بـ \"اليوم الأسود للجيش الألماني\"؛ حيث شكل نقطة تحول نفسية وعسكرية حاسمة. أدركت القيادة الألمانية بعدها أن الحرب خُسرت عسكرياً، وبدأت سلسلة التراجعات المتواصلة التي مهدت للانهيار الشامل."},
  {id:"e64",orderIndex:64,category:"الحرب العالمية الأولى",title:"هجوم المائة يوم (الهجوم المضاد الشامل للحلفاء)",gregorianDate:"8 أغسطس - 11 نوفمبر 1918 م",hijriDate:"30 شوال - 6 صفر 1337 هـ",location:"الجبهة الغربية (بدءاً من معركة أميان)",description:"شن الحلفاء (بقيادة بريطانية وفرنسية وبدعم أمريكي كثيف) سلسلة من الهجمات المنسقة. استخدم الحلفاء تكتيكات الأسلحة المشتركة (تنسيق المشاة، الدبابات، الطيران، والمدفعية) لخرق الدفاعات الألمانية الحصينة (مثل خط هيندنبيرغ) وإجبار الجيش الألماني على تراجع مستمر لا توقف فيه.",strategicSignificance:"أدى هذا الهجوم الماحق إلى انهيار الروح المعنوية والقدرة العسكرية للجيش الألماني. أدركت القيادة العليا الألمانية حتمية الهزيمة، وتزامن ذلك مع الانهيار الداخلي واستسلام حلفاء ألمانيا (بلغاريا، الدولة العثمانية، ثم النمسا والمجر) واحداً تلو الآخر."},
  {id:"e65",orderIndex:65,category:"الحرب العالمية الأولى",title:"تمرد البحارة في ميناء كيل (شرارة الثورة الألمانية)",gregorianDate:"أواخر أكتوبر - أوائل نوفمبر 1918 م",hijriDate:"صفر 1337 هـ",location:"ميناء كيل البحري، ألمانيا",description:"رفض بحارة الأسطول الألماني تنفيذ أوامر القيادة العليا بشن هجوم انتحاري أخير ضد البحرية البريطانية، وتحول هذا الرفض إلى تمرد عسكري سرعان ما تطور إلى ثورة شعبية وعمالية اجتاحت المدن الألمانية الكبرى.",strategicSignificance:"أدى هذا التمرد إلى انهيار الجبهة الداخلية الألمانية تماماً وشل قدرة الدولة على الاستمرار في القتال، مما جعل خيار الاستسلام العسكري أمراً حتمياً لا مفر منه."},
  {id:"e66",orderIndex:66,category:"الحرب العالمية الأولى",title:"تنازل القيصر فيلهلم الثاني عن العرش",gregorianDate:"9 نوفمبر 1918 م",hijriDate:"4 صفر 1337 هـ",location:"برلين (مقر الحكم) ومقر القيادة في بلجيكا",description:"تحت ضغط الهزيمة العسكرية الميدانية والثورة الداخلية المتصاعدة التي أسقطت سيطرة الدولة، أُجبر القيصر الألماني فيلهلم الثاني على التنازل عن العرش والفرار لاحقاً إلى المنفى في هولندا، وتم إعلان تأسيس الجمهورية الألمانية.",strategicSignificance:"مثّل هذا الحدث السقوط النهائي للإمبراطورية الألمانية (الرايخ الثاني)، وأزال العقبة السياسية الأخيرة أمام وفد السلام الألماني لتوقيع هدنة كومبيان، ممهداً الطريق لنشوء \"جمهورية فايمار\"."},
  {id:"e67",orderIndex:67,category:"الحرب العالمية الأولى",title:"توقيع هدنة كومبيان وانتهاء العمليات العسكرية",gregorianDate:"11 نوفمبر 1918 م (دخلت حيز التنفيذ الساعة 11 صباحاً)",hijriDate:"6 صفر 1337 هـ",location:"غابة كومبيان، فرنسا (داخل عربة قطار)",description:"في أعقاب تمرد عسكري داخلي أدى إلى تنازل القيصر الألماني \"فيلهلم الثاني\" عن العرش وإعلان الجمهورية، وقّع الوفد الألماني على اتفاقية هدنة قاسية مع الحلفاء تنص على الوقف الفوري لإطلاق النار، والانسحاب من الأراضي المحتلة، وتسليم العتاد العسكري الثقيل.",strategicSignificance:"أنهت هذه الهدنة أربع سنوات من النزاع الدموي المدمّر، ومثّلت السقوط الفعلي للإمبراطوريات العظمى (الألمانية، الروسية، العثمانية، النمساوية المجرية). كما مهدت الطريق لمؤتمر باريس ومعاهدة فرساي (1919) التي أعادت رسم خريطة العالم وأسست لواقع جيوسياسي جديد."},
  {id:"e68",orderIndex:68,category:"الحرب العالمية الأولى",title:"\"يوم الهدنة\" وتوقف المدافع",gregorianDate:"11 نوفمبر 1918 م (الساعة 11:00 صباحاً)",hijriDate:"صفر 1337 هـ",location:"الجبهة الغربية",description:"دخلت الهدنة - التي وُقعت فجراً في عربة قطار بغابة كومبيان - حيز التنفيذ في الساعة الحادية عشرة من اليوم الحادي عشر من الشهر الحادي عشر. توقف إطلاق النار أخيراً، وخرج الجنود من الجانبين من خنادقهم المدمرة للاحتفال في صمت وحذر متبادل.",strategicSignificance:"مثلت هذه اللحظة النهاية الفعلية للأعمال القتالية في أشرس نزاع شهده التاريخ حتى ذلك الحين. أوقفت الهدنة نزيف الدماء المباشر لـ \"حرب الخنادق\"، ومهدت الطريق لمفاوضات السلام المعقدة التي أعادت هندسة خريطة العالم السياسية والاجتماعية."},
  {id:"e69",orderIndex:69,category:"الحرب العالمية الأولى",title:"إقرار حق التصويت للمرأة الألمانية",gregorianDate:"12 نوفمبر 1918 م",hijriDate:"7 صفر 1337 هـ",location:"ألمانيا",description:"بعد يوم واحد من إعلان الهدنة، حصلت المرأة الألمانية على حقها في التصويت.",strategicSignificance:"يعكس هذا التطور أثراً اجتماعياً عميقاً للحرب الشاملة، حيث أُجبرت الدول على الاعتراف بدور النساء الحيوي في دعم الجبهة الداخلية، مما مهد لتغييرات ديمقراطية كبرى في أوروبا."},
  {id:"e70",orderIndex:70,category:"الحرب العالمية الأولى",title:"احتلال القوات الأمريكية لغرب ألمانيا",gregorianDate:"1 ديسمبر 1918 م",hijriDate:"26 صفر 1337 هـ",location:"المناطق الغربية في ألمانيا",description:"تم دخول القوات الأمريكية إلى المناطق التي احتلتها في غرب ألمانيا كجزء من تنفيذ بنود الهدنة.",strategicSignificance:"رسخ هذا التواجد دور الولايات المتحدة كقوة عظمى مؤثرة في أمن القارة الأوروبية، وشكل بداية للسيطرة العسكرية للحلفاء على أجزاء حيوية من ألمانيا لضمان استسلامها الفعلي."},
  {id:"e71",orderIndex:71,category:"الحرب العالمية الأولى",title:"مؤتمر باريس للسلام",gregorianDate:"18 يناير 1919 م",hijriDate:"16 ربيع الآخر 1337 هـ",location:"باريس، فرنسا",description:"اجتمع قادة الدول المنتصرة (الحلفاء) لصياغة شروط السلام وفرضها على الدول المنهزمة (دول المركز). غابت عن المؤتمر الدول المهزومة وروسيا السوفيتية، وسيطر على القرارات ما عُرف بـ \"الأربعة الكبار\" (قادة بريطانيا، فرنسا، الولايات المتحدة، وإيطاليا).",strategicSignificance:"أسس هذا المؤتمر لنظام دولي جديد، وتمت فيه هندسة خريطة سياسية جديدة للعالم شملت تقسيم إمبراطوريات الوسط المنهزمة، وتوزيع مناطق النفوذ والانتداب (خاصة في الشرق الأوسط)، مما شكل جذوراً للعديد من الصراعات الجيوسياسية المعاصرة."},
  {id:"e72",orderIndex:72,category:"الحرب العالمية الأولى",title:"انتهاء أسر جنود الحلفاء على الجبهة الغربية",gregorianDate:"فبراير 1919 م",hijriDate:"جمادى الأولى 1337 هـ",location:"ألمانيا والجبهة الغربية",description:"تم إطلاق سراح آخر أسير من الحلفاء على الجبهة الغربية ليعودوا إلى أوطانهم بعد شهور من المعاناة.",strategicSignificance:"مثل هذا الحدث خطوة أساسية نحو طي صفحة العمليات العسكرية وتهدئة الجبهات الداخلية في دول الحلفاء التي طالبت باستعادة أبنائها بشدة."},
  {id:"e73",orderIndex:73,category:"الحرب العالمية الأولى",title:"تسريع تطور الطيران المدني والتجاري",gregorianDate:"1919 م",hijriDate:"1337 - 1338 هـ",location:"أوروبا والولايات المتحدة",description:"بعد انتهاء الحرب، تم تحويل آلاف الطائرات العسكرية والطيارين المدربين إلى الاستخدام المدني. أُسست أولى شركات الطيران التجاري، وتم تنظيم أولى الرحلات البريدية والركاب المنتظمة عبر القارات.",strategicSignificance:"حولت الحرب الطيران من مغامرة فردية إلى صناعة منظمة، وأسست للبنية التحتية والخبرات البشرية التي مهدت لثورة الطيران المدني التي غيّرت وجه النقل العالمي."},
  {id:"e74",orderIndex:74,category:"الحرب العالمية الأولى",title:"تصنيف \"المنطقة الحمراء\" (Zone Rouge) وتحدي إعادة الإعمار",gregorianDate:"1919 م وما بعده",hijriDate:"1337 هـ وما بعده",location:"شمال شرق فرنسا وبلجيكا",description:"صنّفت الحكومة الفرنسية مساحات شاسعة من الأراضي التي شهدت أعنف المعارك كـ \"مناطق حمراء\" محظورة السكن والزراعة بسبب التلوث الشديد بالذخائر غير المنفجرة والمواد الكيميائية والجثث المتحللة والتربة المسمومة.",strategicSignificance:"كشفت \"المنطقة الحمراء\" عن الإرث البيئي المدمر والطويل الأمد للحرب الصناعية الحديثة، حيث لا تزال أجزاء منها غير صالحة للاستخدام حتى اليوم بعد أكثر من قرن."},
  {id:"e75",orderIndex:75,category:"الحرب العالمية الأولى",title:"توقيع معاهدة فرساي",gregorianDate:"28 يونيو 1919 م",hijriDate:"29 رمضان 1337 هـ",location:"قصر فرساي، باريس",description:"المعاهدة الرئيسية التي أنهت حالة الحرب رسمياً بين ألمانيا والحلفاء. تضمنت شروطاً قاسية جداً ومذلة على ألمانيا، شملت التجريد العسكري الواسع، ودفع تعويضات مالية ضخمة جداً، واقتطاع أجزاء من أراضيها لصالح دول مجاورة، وتحميلها قانونياً المسؤولية الكاملة عن اندلاع الحرب.",strategicSignificance:"أدت هذه الشروط القاسية إلى انهيار الاقتصاد الألماني لاحقاً وتوليد شعور عميق بالإذلال القومي، مما خلق بيئة سياسية واجتماعية خصبة لظهور الحركات المتطرفة (مثل الحزب النازي) ومهد الطريق فعلياً لاندلاع الحرب العالمية الثانية."},
  {id:"e76",orderIndex:76,category:"الحرب العالمية الأولى",title:"رفض أمريكا لمعاهدة السلام",gregorianDate:"19 نوفمبر 1919 م",hijriDate:"26 صفر 1338 هـ",location:"واشنطن، الولايات المتحدة",description:"بعد الانتهاء من صياغة تسويات ما بعد الحرب، قرر مجلس الشيوخ في الولايات المتحدة الأمريكية رفض معاهدة السلام، وعارض الانضمام إلى المنظومة الدولية الجديدة.",strategicSignificance:"شكل هذا الرفض تحولاً جذرياً نحو سياسة \"الانعزالية\" الأمريكية، وأضعف عصبة الأمم منذ بدايتها لافتقارها لدعم أقوى دولة اقتصادياً وعسكرياً."},
  {id:"e77",orderIndex:77,category:"الحرب العالمية الأولى",title:"تأسيس عصبة الأمم",gregorianDate:"10 يناير 1920 م",hijriDate:"18 ربيع الآخر 1338 هـ",location:"جنيف، سويسرا (المقر الرئيسي)",description:"منظمة دولية تأسست بناءً على المبادئ التي طرحها الرئيس الأمريكي \"وودرو ويلسون\"، بهدف الحفاظ على السلام العالمي، ومنع نشوب حروب مستقبلية عبر تفعيل الدبلوماسية، ونزع السلاح، وتطبيق مبدأ الأمن الجماعي لحل النزاعات بين الدول.",strategicSignificance:"كانت أول محاولة جادة ومؤسسية لتأسيس نظام أمن دولي يجمع دول العالم. ورغم فشلها لاحقاً في منع اندلاع الحرب العالمية الثانية (بسبب افتقارها لقوة عسكرية رادعة وانسحاب قوى كبرى منها)، إلا أنها وضعت الأساس القانوني والتنظيمي الذي بُنيت عليه منظمة \"الأمم المتحدة\" الحالية."},
  {id:"e78",orderIndex:78,category:"الحرب العالمية الأولى",title:"معاهدة سيفر وتقسيم الدولة العثمانية",gregorianDate:"10 أغسطس 1920 م",hijriDate:"25 ذو القعدة 1338 هـ",location:"سيفر، فرنسا",description:"معاهدة سلام فرضها الحلفاء على الدولة العثمانية، نصت على تخلي العثمانيين عن جميع أراضيهم غير الناطقة بالتركية (في بلاد الشام، العراق، وشبه الجزيرة العربية)، وتقسيم أجزاء واسعة من الأناضول بين الحلفاء، مع فرض نظام الانتداب (البريطاني والفرنسي) على الأراضي العربية.",strategicSignificance:"مثّلت النهاية الرسمية والتمزيق الفعلي للإمبراطورية العثمانية، وكرّست واقع اتفاقية (سايكس بيكو)، مما أسس للحدود السياسية الحديثة في الشرق الأوسط. كما أدت قسوة المعاهدة إلى اندلاع حرب الاستقلال التركية التي نجحت في إلغاء المعاهدة واستبدالها بمعاهدة لوزان (1923)."},
  {id:"e79",orderIndex:79,category:"الحرب العالمية الأولى",title:"الإفراج عن أسرى الحرب الألمان",gregorianDate:"أكتوبر 1919 م - خريف 1920 م",hijriDate:"محرم 1338 هـ - صفر 1339 هـ",location:"بريطانيا وفرنسا",description:"شهدت هذه الفترة إطلاق سراح آخر أسير ألماني في قبضة القوات البريطانية في أكتوبر 1919، وتلا ذلك في العام التالي إطلاق سراح آخر أسير ألماني أسر على يد القوات الفرنسية.",strategicSignificance:"عكس التأخير الطويل في الإفراج عن الأسرى الألمان مقارنة بأسرى الحلفاء حجم التوتر والمرارة التي خلفتها الحرب، حيث استُخدم الأسرى كورقة ضغط في مفاوضات ما بعد الحرب."},
  {id:"e80",orderIndex:80,category:"الحرب العالمية الأولى",title:"تراجع نفوذ الطبقة الأرستقراطية والنبلاء",gregorianDate:"ما بعد 1918 م",hijriDate:"1337 هـ وما بعده",location:"أوروبا بشكل عام",description:"أدت الحرب إلى تآكل حاد في نفوذ الطبقة الأرستقراطية التي كانت تهيمن تقليدياً على المناصب العسكرية والسياسية العليا. فقدت عائلات نبيلة كثيرة أبناءها في الحرب، وسقطت إمبراطوريات كانت تقودها (الروسية والألمانية والنمساوية المجرية والعثمانية).",strategicSignificance:"مثّل هذا التراجع تحولاً اجتماعياً عميقاً نحو مجتمعات أكثر ديمقراطية ومساواة، وأفسح المجال لصعود الطبقات الوسطى والعاملة إلى مواقع السلطة والتأثير."},
  {id:"e81",orderIndex:81,category:"الحرب العالمية الأولى",title:"صعود الأدب والفن المناهض للحرب",gregorianDate:"1919 - 1930 م",hijriDate:"1337 - 1349 هـ",location:"أوروبا والعالم الغربي",description:"أنتج جيل من الكتّاب والفنانين الذين عاشوا تجربة الخنادق أعمالاً أدبية وفنية مناهضة للحرب أصبحت من أهم الأعمال في القرن العشرين، مثل روايات إريك ماريا ريمارك وأشعار ويلفريد أوين وسيغفريد ساسون ولوحات أوتو ديكس.",strategicSignificance:"غيّر هذا الأدب والفن بشكل جذري الطريقة التي ينظر بها المجتمع إلى الحرب، وحوّلها من \"مجد وشرف\" إلى \"عبث ومأساة\"، مما أثر على الوعي الجماعي تجاه النزاعات المسلحة لأجيال لاحقة."},
  {id:"e82",orderIndex:82,category:"الحرب العالمية الأولى",title:"توقيع اتفاقية السلام الأمريكية الألمانية المستقلة",gregorianDate:"25 أغسطس 1921 م",hijriDate:"20 ذو الحجة 1339 هـ",location:"برلين، ألمانيا",description:"بهدف إنهاء حالة العداء بشكل قانوني، قامت الولايات المتحدة بتوقيع اتفاقية سلام منفصلة مع ألمانيا (معاهدة برلين).",strategicSignificance:"أنهى هذا الحدث التداعيات القانونية للحرب بالنسبة للولايات المتحدة بعيداً عن تعقيدات وشروط معاهدة فرساي الأوروبية، وأسس لمسار علاقات ثنائية جديدة خارج مظلة عصبة الأمم."},
];
